        int n = s.length();
        vector<bool> answer(queries.size());
        for (int i = 0; i < queries.size(); i++) {
            int a = queries[i][0], b = queries[i][1], c = queries[i][2], d = queries[i][3];
            string first = s.substr(a, b - a + 1);
            string second = s.substr(c, d - c + 1);
            string firstRev = first;
            reverse(firstRev.begin(), firstRev.end());
            string secondRev = second;
            reverse(secondRev.begin(), secondRev.end());
            answer[i] = (first == firstRev || second == secondRev);
        }
        return answer;
    }
};
